UPDATE public.questions SET
  stimulus_text = 'Many people believe that the best way to save money is to reduce spending. This is a common piece of advice, and often, it is effective. However, sometimes, it is more effective to increase your income, rather than to reduce your spending.  Ultimately, the best way to save money is to have more money coming in than going out. Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
  question_text = 'Which choice best combines the sentences at the underlined portion of the passage? ',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"This is a common piece of advice, and it is often effective.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"This is a common piece of advice; it is often effective.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"This is a common piece of advice, often it is effective.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"This is a common piece of advice, and, often, it is effective.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The most effective way to combine these two sentences is to use a comma and the coordinating conjunction "and." This creates a grammatically correct sentence that flows smoothly. The other choices create incorrect punctuation, or they don’t combine the sentences effectively.  Choice B uses a semicolon, but semicolons should only be used to separate two independent clauses, and the two clauses in the underlined portion of the sentence aren’t independent.  Choice C includes a comma but no coordinating conjunction, which creates a comma splice error.  Choice D uses both a comma and a coordinating conjunction, but the comma is unnecessary, making the sentence unnecessarily complex. The passage states that "Many people believe that the best way to save money is to reduce spending. This is a common piece of advice, and often, …", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: This is a common piece of advice, and it is often effective.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":880,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_a1","opensat_difficulty":"Medium","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.913Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
