UPDATE public.questions SET
  stimulus_text = 'Engineers prototyping turbine 15 demonstrated that angled blades harvest more energy from low wind speeds, a design inspired by the shape of humpback whale fins. Standard flat blades stall when air flow separates early, wasting kinetic energy that never reaches the generator. The prototype''s tubercle-like ridges delay separation, maintaining lift across a wider range of wind speeds common in residential installations. Wind-tunnel tests documented a twelve-percent gain at moderate speeds without increasing noise above local ordinance limits. The engineers note that biomimicry here is not decorative; it directly addresses a performance bottleneck that limits small-scale renewable adoption. The passage moves from biological observation to mechanical testing to a practical deployment implication.',
  question_text = 'According to the passage, which statement is best supported by the text?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"The passage links parrotfish grazing limits algae growth to measurable reef recovery after disturbance.","is_correct":true,"explanation":"The passage explicitly discusses parrotfish grazing limits algae growth as evidence tied to reef health. This answer restates that supported relationship without overclaiming."},{"id":"B","text":"Reefs never recover once algae appear, regardless of grazing or recruitment.","is_correct":false,"explanation":"The passage describes recovery mechanisms; it does not claim reefs are permanently lost once algae appear."},{"id":"C","text":"The passage rejects scientific study of reefs in favor of anecdotal fishing reports.","is_correct":false,"explanation":"The passage cites research and field surveys; it does not reject scientific methods."},{"id":"D","text":"Coral larvae cannot survive on any hard surface mentioned in marine research.","is_correct":false,"explanation":"The passage states larvae settle on bare rock when grazing permits it, contradicting this absolute claim."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The passage explains how grazing, algae growth, and coral settlement interact to shape reef recovery. The author supports this main idea with seasonal tracking data and comparisons across sites with different parrotfish abundance. Choice A synthesizes that evidence without adding unsupported claims. The wrong answers either overstate permanence, mischaracterize the author''s stance toward science, or deny details the passage affirms.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"original":true,"generator":"scholaris_bulk_v1","explanation_v2":true,"english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.877Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
WHERE id = 'c5aee675-052c-4fc1-913c-45167676084e';
UPDATE public.questions SET
  stimulus_text = 'Educators reviewing literacy program 16 concluded that students who discussed readings in pairs improved comprehension scores more than those who answered worksheets alone. Teachers in the pair-discussion classrooms reported that students referenced textual evidence when disagreeing, a behavior rarely observed during silent worksheet completion. Standardized pre- and post-tests showed a twelve-point average gain for the discussion cohort versus a four-point gain for the worksheet cohort over the same six-week unit. The educators emphasize that discussion prompts were structured—not unstructured chat—and required each partner to cite a line from the text. They argue that collaborative talk externalizes comprehension strategies that weaker readers otherwise keep invisible. The passage supports structured peer dialogue as an instructional lever rather than a replacement for independent reading.',
